<template><div class='modern-page'><section class='modern-hero'><h1>Simulador de Elegibilidade</h1><p>Valida documentos, regra de 1/3 salarial e condições de 50 mil / 51 a 100 mil.</p><div class='hero-actions'><span class='hero-chip'>Até 50 mil: menos de 24h se elegível</span><span class='hero-chip'>51–100 mil: cartório/escritório</span></div></section><div class='modern-grid-2'><div class='modern-card'><h2>Dados</h2><div class='form-grid'><input class='input' v-model.number='amount' type='number' placeholder='Valor'><input class='input' v-model.number='salary' type='number' placeholder='Salário líquido'><input class='input' v-model.number='term' type='number' placeholder='Prazo'><input class='input' v-model.number='burden' type='number' placeholder='Outros descontos'></div><div class='doc-check'><label v-for='d in docs' :key='d'><input type='checkbox' v-model='checked' :value='d'>{{d}}</label><label><input type='checkbox' v-model='payroll'>Folha de salário (opcional)</label></div><button class='btn btn-primary btn-block' @click='simulate'>Verificar condições</button></div><div class='modern-card'><h2>Resultado</h2><div v-if='result'><div class='kpi' :class='result.ok?"good":"danger"'><div class='label'>Prestação</div><div class='value'>{{mzn(result.installment)}}</div><div class='note'>Limite disponível: {{mzn(result.limit)}}</div></div><div class='notice' :class='result.ok?"":"danger"'>{{result.message}}</div><button class='btn btn-primary' :disabled='!result.ok' @click="toast.success('Pedido submetido para aprovação administrativa')">Submeter pedido</button></div><div v-else class='empty-state'>Preencha e verifique.</div></div></div></div></template><script setup>
import { ref, computed } from 'vue'; import { useToast } from 'vue-toastification'; const toast=useToast(); function mzn(v){return Number(v||0).toLocaleString('pt-MZ',{style:'currency',currency:'MZN',maximumFractionDigits:0})} function st(s){return 'status-pill st-'+s}
const docs=['BI','NUIT','Atestado de residência','Extracto bancário 3 meses']; const checked=ref([...docs]); const payroll=ref(true); const amount=ref(45000),salary=ref(25000),term=ref(18),burden=ref(3000),result=ref(null); function simulate(){const installment=amount.value/term.value*1.32, limit=salary.value/3-burden.value, docsOk=checked.value.length===4; let ok=docsOk&&installment<=limit; let message='Cliente reúne condições documentais e financeiras.'; if(!docsOk)message='Bloqueado: faltam documentos obrigatórios.'; else if(installment>limit)message='Excede 1/3 salarial. Enviar para análise com bens/garantias.'; else if(amount.value<=50000)message='Elegível: abaixo de 50.000 MZN, desembolso em menos de 24h se aprovado.'; else if(amount.value<=100000)message='Elegível condicionado a documento reconhecido no cartório/escritório.'; result.value={ok,installment,limit,message}}
</script>